    16→package com.github.rjeschke.txtmark;
    17→
    18→import java.util.ArrayList;
    19→import java.util.HashMap;
    20→
    21→/**
    22→ * Emitter class responsible for generating HTML output.
    23→ *
    24→ * @author René Jeschke <rene_jeschke@yahoo.de>
    25→ */
    26→class Emitter
    27→{
    28→    /** Link references. */
    29→    private final HashMap<String, LinkRef> linkRefs      = new HashMap<String, LinkRef>();
    30→    /** The configuration. */
    31→    private final Configuration            config;
    32→    /** Extension flag. */
    33→    public boolean                         useExtensions = false;
    34→
    35→    /** Constructor. */
    36→    public Emitter(final Configuration config)
    37→    {
    38→        this.config = config;
    39→        this.useExtensions = config.forceExtendedProfile;
    40→    }
    41→
    42→    /**
    43→     * Adds a LinkRef to this set of LinkRefs.
    44→     *
    45→     * @param key
    46→     *            The key/id.
    47→     * @param linkRef
    48→     *            The LinkRef.
    49→     */
    50→    public void addLinkRef(final String key, final LinkRef linkRef)
    51→    {
    52→        this.linkRefs.put(key.toLowerCase(), linkRef);
    53→    }
    54→
    55→    /**
    56→     * Transforms the given block recursively into HTML.
    57→     *
    58→     * @param out
    59→     *            The StringBuilder to write to.
    60→     * @param root
    61→     *            The Block to process.
    62→     */
    63→    public void emit(final StringBuilder out, final Block root)
    64→    {
    65→        root.removeSurroundingEmptyLines();
    66→
    67→        switch (root.type)
    68→        {
    69→        case RULER:
    70→            this.config.decorator.horizontalRuler(out);
    71→            return;
    72→        case NONE:
    73→        case XML:
    74→            break;
    75→        case HEADLINE:
    76→            this.config.decorator.openHeadline(out, root.hlDepth);
    77→            if (this.useExtensions && root.id != null)
    78→            {
    79→                out.append(" id=\"");
    80→                Utils.appendCode(out, root.id, 0, root.id.length());
    81→                out.append('"');
    82→            }
    83→            out.append('>');
    84→            break;
    85→        case PARAGRAPH:
    86→            this.config.decorator.openParagraph(out);
    87→            break;
    88→        case CODE:
    89→        case FENCED_CODE:
    90→            if (this.config.codeBlockEmitter == null)
    91→            {
    92→                this.config.decorator.openCodeBlock(out);
    93→            }
    94→            break;
    95→        case BLOCKQUOTE:
    96→            this.config.decorator.openBlockquote(out);
    97→            break;
    98→        case UNORDERED_LIST:
    99→            this.config.decorator.openUnorderedList(out);
   100→            break;
   101→        case ORDERED_LIST:
   102→            this.config.decorator.openOrderedList(out);
   103→            break;
   104→        case LIST_ITEM:
   105→            this.config.decorator.openListItem(out);
   106→            if (this.useExtensions && root.id != null)
   107→            {
   108→                out.append(" id=\"");
   109→                Utils.appendCode(out, root.id, 0, root.id.length());
   110→                out.append('"');
   111→            }
   112→            out.append('>');
   113→            break;
   114→        }
   115→
   116→        if (root.hasLines())
   117→        {
   118→            this.emitLines(out, root);
   119→        }
   120→        else
   121→        {
   122→            Block block = root.blocks;
   123→            while (block != null)
   124→            {
   125→                this.emit(out, block);
   126→                block = block.next;
   127→            }
   128→        }
   129→
   130→        switch (root.type)
   131→        {
   132→        case RULER:
   133→        case NONE:
   134→        case XML:
   135→            break;
   136→        case HEADLINE:
   137→            this.config.decorator.closeHeadline(out, root.hlDepth);
   138→            break;
   139→        case PARAGRAPH:
   140→            this.config.decorator.closeParagraph(out);
   141→            break;
   142→        case CODE:
   143→        case FENCED_CODE:
   144→            if (this.config.codeBlockEmitter == null)
   145→            {
   146→                this.config.decorator.closeCodeBlock(out);
   147→            }
   148→            break;
   149→        case BLOCKQUOTE:
   150→            this.config.decorator.closeBlockquote(out);
   151→            break;
   152→        case UNORDERED_LIST:
   153→            this.config.decorator.closeUnorderedList(out);
   154→            break;
   155→        case ORDERED_LIST:
   156→            this.config.decorator.closeOrderedList(out);
   157→            break;
   158→        case LIST_ITEM:
   159→            this.config.decorator.closeListItem(out);
   160→            break;
   161→        }
   162→    }
   163→
   164→    /**
   165→     * Transforms lines into HTML.
   166→     *
   167→     * @param out
   168→     *            The StringBuilder to write to.
   169→     * @param block
   170→     *            The Block to process.
   171→     */
   172→    private void emitLines(final StringBuilder out, final Block block)
   173→    {
   174→        switch (block.type)
   175→        {
   176→        case CODE:
   177→            this.emitCodeLines(out, block.lines, block.meta, true);
   178→            break;
   179→        case FENCED_CODE:
   180→            this.emitCodeLines(out, block.lines, block.meta, false);
   181→            break;
   182→        case XML:
   183→            this.emitRawLines(out, block.lines);
   184→            break;
   185→        default:
   186→            this.emitMarkedLines(out, block.lines);
   187→            break;
   188→        }
   189→    }
   190→
   191→    /**
   192→     * Finds the position of the given Token in the given String.
   193→     *
   194→     * @param in
   195→     *            The String to search on.
   196→     * @param start
   197→     *            The starting character position.
   198→     * @param token
   199→     *            The token to find.
   200→     * @return The position of the token or -1 if none could be found.
   201→     */
   202→    private int findToken(final String in, final int start, final MarkToken token)
   203→    {
   204→        int pos = start;
   205→        while (pos < in.length())
   206→        {
   207→            if (this.getToken(in, pos) == token)
   208→            {
   209→                return pos;
   210→            }
   211→            pos++;
   212→        }
   213→        return -1;
   214→    }
   215→
   216→    /**
   217→     * Checks if there is a valid markdown link definition.
   218→     *
   219→     * @param out
   220→     *            The StringBuilder containing the generated output.
   221→     * @param in
   222→     *            Input String.
   223→     * @param start
   224→     *            Starting position.
   225→     * @param token
   226→     *            Either LINK or IMAGE.
   227→     * @return The new position or -1 if there is no valid markdown link.
   228→     */
   229→    private int checkLink(final StringBuilder out, final String in, final int start, final MarkToken token)
   230→    {
   231→        boolean isAbbrev = false;
   232→        int pos = start + (token == MarkToken.LINK ? 1 : 2);
   233→        final StringBuilder temp = new StringBuilder();
   234→
   235→        temp.setLength(0);
   236→        pos = Utils.readMdLinkId(temp, in, pos);
   237→        if (pos < start)
   238→        {
   239→            return -1;
   240→        }
   241→
   242→        final String name = temp.toString();
   243→        String link = null, comment = null;
   244→        final int oldPos = pos++;
   245→        pos = Utils.skipSpaces(in, pos);
   246→        if (pos < start)
   247→        {
   248→            final LinkRef lr = this.linkRefs.get(name.toLowerCase());
   249→            if (lr != null)
   250→            {
   251→                isAbbrev = lr.isAbbrev;
   252→                link = lr.link;
   253→                comment = lr.title;
   254→                pos = oldPos;
   255→            }
   256→            else
   257→            {
   258→                return -1;
   259→            }
   260→        }
   261→        else if (in.charAt(pos) == '(')
   262→        {
   263→            pos++;
   264→            pos = Utils.skipSpaces(in, pos);
   265→            if (pos < start)
   266→            {
   267→                return -1;
   268→            }
   269→            temp.setLength(0);
   270→            final boolean useLt = in.charAt(pos) == '<';
   271→            pos = useLt ? Utils.readUntil(temp, in, pos + 1, '>') : Utils.readMdLink(temp, in, pos);
   272→            if (pos < start)
   273→            {
   274→                return -1;
   275→            }
   276→            if (useLt)
   277→            {
   278→                pos++;
   279→            }
   280→            link = temp.toString();
   281→
   282→            if (in.charAt(pos) == ' ')
   283→            {
   284→                pos = Utils.skipSpaces(in, pos);
   285→                if (pos > start && in.charAt(pos) == '"')
   286→                {
   287→                    pos++;
   288→                    temp.setLength(0);
   289→                    pos = Utils.readUntil(temp, in, pos, '"');
   290→                    if (pos < start)
   291→                    {
   292→                        return -1;
   293→                    }
   294→                    comment = temp.toString();
   295→                    pos++;
   296→                    pos = Utils.skipSpaces(in, pos);
   297→                    if (pos == -1)
   298→                    {
   299→                        return -1;
   300→                    }
   301→                }
   302→            }
   303→            if (in.charAt(pos) != ')')
   304→            {
   305→                return -1;
   306→            }
   307→        }
   308→        else if (in.charAt(pos) == '[')
   309→        {
   310→            pos++;
   311→            temp.setLength(0);
   312→            pos = Utils.readRawUntil(temp, in, pos, ']');
   313→            if (pos < start)
   314→            {
   315→                return -1;
   316→            }
   317→            final String id = temp.length() > 0 ? temp.toString() : name;
   318→            final LinkRef lr = this.linkRefs.get(id.toLowerCase());
   319→            if (lr != null)
   320→            {
   321→                link = lr.link;
   322→                comment = lr.title;
   323→            }
   324→        }
   325→        else
   326→        {
   327→            final LinkRef lr = this.linkRefs.get(name.toLowerCase());
   328→            if (lr != null)
   329→            {
   330→                isAbbrev = lr.isAbbrev;
   331→                link = lr.link;
   332→                comment = lr.title;
   333→                pos = oldPos;
   334→            }
   335→            else
   336→            {
   337→                return -1;
   338→            }
   339→        }
   340→
   341→        if (link == null)
   342→        {
   343→            return -1;
   344→        }
   345→
   346→        if (token == MarkToken.LINK)
   347→        {
   348→            if (isAbbrev && comment != null)
   349→            {
   350→                if (!this.useExtensions)
   351→                {
   352→                    return -1;
   353→                }
   354→                out.append("<abbr title=\"");
   355→                Utils.appendValue(out, comment, 0, comment.length());
   356→                out.append("\">");
   357→                this.recursiveEmitLine(out, name, 0, MarkToken.NONE);
   358→                out.append("</abbr>");
   359→            }
   360→            else
   361→            {
   362→                this.config.decorator.openLink(out);
   363→                out.append(" href=\"");
   364→                Utils.appendValue(out, link, 0, link.length());
   365→                out.append('"');
   366→                if (comment != null)
   367→                {
   368→                    out.append(" title=\"");
   369→                    Utils.appendValue(out, comment, 0, comment.length());
   370→                    out.append('"');
   371→                }
   372→                out.append('>');
   373→                this.recursiveEmitLine(out, name, 0, MarkToken.NONE);
   374→                this.config.decorator.closeLink(out);
   375→            }
   376→        }
   377→        else
   378→        {
   379→            this.config.decorator.openImage(out);
   380→            out.append(" src=\"");
   381→            Utils.appendValue(out, link, 0, link.length());
   382→            out.append("\" alt=\"");
   383→            Utils.appendValue(out, name, 0, name.length());
   384→            out.append('"');
   385→            if (comment != null)
   386→            {
   387→                out.append(" title=\"");
   388→                Utils.appendValue(out, comment, 0, comment.length());
   389→                out.append('"');
   390→            }
   391→            this.config.decorator.closeImage(out);
   392→        }
   393→
   394→        return pos;
   395→    }
   396→
   397→    /**
   398→     * Check if there is a valid HTML tag here. This method also transforms auto
   399→     * links and mailto auto links.
   400→     *
   401→     * @param out
   402→     *            The StringBuilder to write to.
   403→     * @param in
   404→     *            Input String.
   405→     * @param start
   406→     *            Starting position.
   407→     * @return The new position or -1 if nothing valid has been found.
   408→     */
   409→    private int checkHtml(final StringBuilder out, final String in, final int start)
   410→    {
   411→        final StringBuilder temp = new StringBuilder();
   412→        int pos;
   413→
   414→        // Check for auto links
   415→        temp.setLength(0);
   416→        pos = Utils.readUntil(temp, in, start + 1, ':', ' ', '>', '\n');
   417→        if (pos != -1 && in.charAt(pos) == ':' && HTML.isLinkPrefix(temp.toString()))
   418→        {
   419→            pos = Utils.readUntil(temp, in, pos, '>');
   420→            if (pos != -1)
   421→            {
   422→                final String link = temp.toString();
   423→                this.config.decorator.openLink(out);
   424→                out.append(" href=\"");
   425→                Utils.appendValue(out, link, 0, link.length());
   426→                out.append("\">");
   427→                Utils.appendValue(out, link, 0, link.length());
   428→                this.config.decorator.closeLink(out);
   429→                return pos;
   430→            }
   431→        }
   432→
   433→        // Check for mailto auto link
   434→        temp.setLength(0);
   435→        pos = Utils.readUntil(temp, in, start + 1, '@', ' ', '>', '\n');
   436→        if (pos != -1 && in.charAt(pos) == '@')
   437→        {
   438→            pos = Utils.readUntil(temp, in, pos, '>');
   439→            if (pos != -1)
   440→            {
   441→                final String link = temp.toString();
   442→                this.config.decorator.openLink(out);
   443→                out.append(" href=\"");
   444→                Utils.appendMailto(out, "mailto:", 0, 7);
   445→                Utils.appendMailto(out, link, 0, link.length());
   446→                out.append("\">");
   447→                Utils.appendMailto(out, link, 0, link.length());
   448→                this.config.decorator.closeLink(out);
   449→                return pos;
   450→            }
   451→        }
   452→
   453→        // Check for inline html
   454→        if (start + 2 < in.length())
   455→        {
   456→            temp.setLength(0);
   457→            return Utils.readXML(out, in, start, this.config.safeMode);
   458→        }
   459→
   460→        return -1;
   461→    }
   462→
   463→    /**
   464→     * Check if this is a valid XML/HTML entity.
   465→     *
   466→     * @param out
   467→     *            The StringBuilder to write to.
   468→     * @param in
   469→     *            Input String.
   470→     * @param start
   471→     *            Starting position
   472→     * @return The new position or -1 if this entity in invalid.
   473→     */
   474→    private static int checkEntity(final StringBuilder out, final String in, final int start)
   475→    {
   476→        final int pos = Utils.readUntil(out, in, start, ';');
   477→        if (pos < 0 || out.length() < 3)
   478→        {
   479→            return -1;
   480→        }
   481→        if (out.charAt(1) == '#')
   482→        {
   483→            if (out.charAt(2) == 'x' || out.charAt(2) == 'X')
   484→            {
   485→                if (out.length() < 4)
   486→                {
   487→                    return -1;
   488→                }
   489→                for (int i = 3; i < out.length(); i++)
   490→                {
   491→                    final char c = out.charAt(i);
   492→                    if ((c < '0' || c > '9') && ((c < 'a' || c > 'f') && (c < 'A' || c > 'F')))
   493→                    {
   494→                        return -1;
   495→                    }
   496→                }
   497→            }
   498→            else
   499→            {
   500→                for (int i = 2; i < out.length(); i++)
   501→                {
   502→                    final char c = out.charAt(i);
   503→                    if (c < '0' || c > '9')
   504→                    {
   505→                        return -1;
   506→                    }
   507→                }
   508→            }
   509→            out.append(';');
   510→        }
   511→        else
   512→        {
   513→            for (int i = 1; i < out.length(); i++)
   514→            {
   515→                final char c = out.charAt(i);
   516→                if (!Character.isLetterOrDigit(c))
   517→                {
   518→                    return -1;
   519→                }
   520→            }
   521→            out.append(';');
   522→            return HTML.isEntity(out.toString()) ? pos : -1;
   523→        }
   524→
   525→        return pos;
   526→    }
   527→
   528→    /**
   529→     * Recursively scans through the given line, taking care of any markdown
   530→     * stuff.
   531→     *
   532→     * @param out
   533→     *            The StringBuilder to write to.
   534→     * @param in
   535→     *            Input String.
   536→     * @param start
   537→     *            Start position.
   538→     * @param token
   539→     *            The matching Token (for e.g. '*')
   540→     * @return The position of the matching Token or -1 if token was NONE or no
   541→     *         Token could be found.
   542→     */
   543→    private int recursiveEmitLine(final StringBuilder out, final String in, final int start, final MarkToken token)
   544→    {
   545→        int pos = start, a, b;
   546→        final StringBuilder temp = new StringBuilder();
   547→        while (pos < in.length())
   548→        {
   549→            final MarkToken mt = this.getToken(in, pos);
   550→            if (token != MarkToken.NONE
   551→                    && (mt == token || token == MarkToken.EM_STAR && mt == MarkToken.STRONG_STAR || token == MarkToken.EM_UNDERSCORE
   552→                            && mt == MarkToken.STRONG_UNDERSCORE))
   553→            {
   554→                return pos;
   555→            }
   556→
   557→            switch (mt)
   558→            {
   559→            case IMAGE:
   560→            case LINK:
   561→                temp.setLength(0);
   562→                b = this.checkLink(temp, in, pos, mt);
   563→                if (b > 0)
   564→                {
   565→                    out.append(temp);
   566→                    pos = b;
   567→                }
   568→                else
   569→                {
   570→                    out.append(in.charAt(pos));
   571→                }
   572→                break;
   573→            case EM_STAR:
   574→            case EM_UNDERSCORE:
   575→                temp.setLength(0);
   576→                b = this.recursiveEmitLine(temp, in, pos + 1, mt);
   577→                if (b > 0)
   578→                {
   579→                    this.config.decorator.openEmphasis(out);
   580→                    out.append(temp);
   581→                    this.config.decorator.closeEmphasis(out);
   582→                    pos = b;
   583→                }
   584→                else
   585→                {
   586→                    out.append(in.charAt(pos));
   587→                }
   588→                break;
   589→            case STRONG_STAR:
   590→            case STRONG_UNDERSCORE:
   591→                temp.setLength(0);
   592→                b = this.recursiveEmitLine(temp, in, pos + 2, mt);
   593→                if (b > 0)
   594→                {
   595→                    this.config.decorator.openStrong(out);
   596→                    out.append(temp);
   597→                    this.config.decorator.closeStrong(out);
   598→                    pos = b + 1;
   599→                }
   600→                else
   601→                {
   602→                    out.append(in.charAt(pos));
   603→                }
   604→                break;
   605→            case SUPER:
   606→                temp.setLength(0);
   607→                b = this.recursiveEmitLine(temp, in, pos + 1, mt);
   608→                if (b > 0)
   609→                {
   610→                    this.config.decorator.openSuper(out);
   611→                    out.append(temp);
   612→                    this.config.decorator.closeSuper(out);
   613→                    pos = b;
   614→                }
   615→                else
   616→                {
   617→                    out.append(in.charAt(pos));
   618→                }
   619→                break;
   620→            case CODE_SINGLE:
   621→            case CODE_DOUBLE:
   622→                a = pos + (mt == MarkToken.CODE_DOUBLE ? 2 : 1);
   623→                b = this.findToken(in, a, mt);
   624→                if (b > 0)
   625→                {
   626→                    pos = b + (mt == MarkToken.CODE_DOUBLE ? 1 : 0);
   627→                    while (a < b && in.charAt(a) == ' ')
   628→                    {
   629→                        a++;
   630→                    }
   631→                    if (a < b)
   632→                    {
   633→                        while (in.charAt(b - 1) == ' ')
   634→                        {
   635→                            b--;
   636→                        }
   637→                        this.config.decorator.openCodeSpan(out);
   638→                        Utils.appendCode(out, in, a, b);
   639→                        this.config.decorator.closeCodeSpan(out);
   640→                    }
   641→                }
   642→                else
   643→                {
   644→                    out.append(in.charAt(pos));
   645→                }
   646→                break;
   647→            case HTML:
   648→                temp.setLength(0);
   649→                b = this.checkHtml(temp, in, pos);
   650→                if (b > 0)
   651→                {
   652→                    out.append(temp);
   653→                    pos = b;
   654→                }
   655→                else
   656→                {
   657→                    out.append("&lt;");
   658→                }
   659→                break;
   660→            case ENTITY:
   661→                temp.setLength(0);
   662→                b = checkEntity(temp, in, pos);
   663→                if (b > 0)
   664→                {
   665→                    out.append(temp);
   666→                    pos = b;
   667→                }
   668→                else
   669→                {
   670→                    out.append("&amp;");
   671→                }
   672→                break;
   673→            case X_LINK_OPEN:
   674→                temp.setLength(0);
   675→                b = this.recursiveEmitLine(temp, in, pos + 2, MarkToken.X_LINK_CLOSE);
   676→                if (b > 0 && this.config.specialLinkEmitter != null)
   677→                {
   678→                    this.config.specialLinkEmitter.emitSpan(out, temp.toString());
   679→                    pos = b + 1;
